import React, { useEffect, useState } from "react";
import { Link } from 'react-router-dom';
import { CButton, CDropdownItem, CDropdownMenu, CDropdownToggle, CDropdown } from "@coreui/react";
import { customStyles } from "../../../utils/tableCustomStyles";
import { tableSignupUserListConstant } from "./tablePaymentLinkConstant";
import DataTable from "react-data-table-component";
import authService from "src/auth/auth.service";
import { getSignupUserList } from "src/components/services/SubscriptionApi";
import { FilterComponent } from "src/utils/FilterComponent";

function SummaryList() {
    const [rowData, setRowData] = useState([]);
    const [loading, setLoading] = useState(false)
    const [totalRows, setTotalRows] = useState(0);
    const [perPage, setPerPage] = useState(10);
    const [filterData, setFilterData] = useState({filterText: "",  filterType: "", isSearchDisabled: true});
    const [searchDataList,setSearchDataList] = useState([]);
    const [isApplySearch, setIsApplySearch] = useState(false)


    useEffect(() => {
        fetchSignupUserList(0,perPage);
    }, []);


    const fetchSignupUserList = async (page,size) => {
        let data = {
            page: page,
            size: size
        }
        setLoading(true)
        const response = await getSignupUserList(data);
        if (response?.status === "200 OK") {
            setRowData(response?.body?.content);
            setTotalRows(response?.body?.totalElements)
            setLoading(false)
        }
    };

    const handlePageChange = (page) => {
        fetchSignupUserList(page-1, perPage);
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        setPerPage(newPerPage);
        fetchSignupUserList(page-1, newPerPage);
    };

    const handleChangeFilter = (event) => {
        setFilterData((filterData) => ({ ...filterData, filterText: event.target.value.trim(), isSearchDisabled: false}));
    };

    const handleClearSearch = () => {
        setFilterData((filterData) => ({ ...filterData, filterType: "", filterText: "", isSearchDisabled: true}));
        setSearchDataList([]),
        setIsApplySearch(false);
    }

    const changeSearchData = (data) => {
        setFilterData((filterData) => ({ ...filterData, filterType: data, filterText: "", isSearchDisabled: true}));
        setSearchDataList([]);
        setIsApplySearch(false);
    }

    const getSubHeaderComponent = () => {
        return (
            <React.Fragment>
                <CDropdown >
                    <CDropdownToggle> Search by <strong>{filterData?.filterType}</strong></CDropdownToggle>
                    <CDropdownMenu>
                        <CDropdownItem onClick={() => changeSearchData("Name")}>Name</CDropdownItem>
                        <CDropdownItem onClick={() => changeSearchData("Email")}>Email</CDropdownItem>
                    </CDropdownMenu>
                </CDropdown>
                <div>
                    <FilterComponent onFilter={handleChangeFilter} searchType={'Search...'} filterText={filterData?.filterText} />
                    <span class="search-close" onClick={() => handleClearSearch()}></span>
                </div>
            </React.Fragment>
        );
    };

    const actionButton = () => {
        return (
            <React.Fragment>
                {getSubHeaderComponent()}
                <CButton type="submit" color="primary" className="addRoleGlobal" style={{ float: "right" }} disabled={filterData?.isSearchDisabled} onClick={handleApplySearch}> <i class="fa fa-search" /> Search</CButton>
            </React.Fragment>
        );
    };

    const handleApplySearch = () => {
        let filterItems = rowData && rowData.filter(item => item?.[filterData?.filterType === "Name" ? "firstName" : "email"]?.toLowerCase().includes(filterData?.filterText.toLowerCase()))
        setIsApplySearch(true);
        setSearchDataList(filterItems)
    }


    return (
        <div className='row'>
            <div className="col2Large">
                <DataTable
                    title="Members summary"
                    columns={tableSignupUserListConstant()}
                    data={isApplySearch ? searchDataList : rowData}
                    customStyles={customStyles}
                    actions={actionButton()}
                    pagination
                    paginationPerPage={perPage}
                    pointerOnHover
                    progressPending={loading}
                    paginationServer
                    paginationTotalRows={totalRows}
                    onChangeRowsPerPage={handlePerRowsChange}
                    onChangePage={handlePageChange}
                    fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                />
            </div>
            {authService.getPermission("PAYMENT_LINK_CREATE") && <div className='col-sm-12'>
                <Link to={"/subscription-summary/create"}>
                    <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                        {"+ Generate Payment Link"}
                    </CButton>
                </Link>
            </div>}
        </div>
    );
}

export default SummaryList;
